import React, { useState, useEffect, useMemo } from 'react';
import { MENU_DATA, CHEF_LOGO } from './data';
import { MenuItemCard } from './components/MenuItemCard';
import { LanguageSelector } from './components/LanguageSelector';
import { PrintMenuModal } from './components/PrintMenuModal';
import { AdminLoginModal } from './components/AdminLoginModal';
import { OrderNotepad } from './components/OrderNotepad';
import { QRCodeModal } from './components/QRCodeModal';
import { translations } from './translations';
import { Language, MenuItem, CartItem, Category } from './types';
import { Search, Phone, ChevronDown, Unlock, ClipboardList, ArrowRight, Printer, QrCode, RefreshCcw, MapPin, Clock, CloudUpload, AlertTriangle, CheckCircle } from 'lucide-react';

const PHONE_NUMBER = "281325175"; 
const FORMATTED_PHONE = "281 325 175";

const OrderButtons: React.FC<{ lang: Language }> = ({ lang }) => {
  const t = translations[lang];
  return (
    <div className="flex flex-row gap-3 w-full max-w-lg mx-auto my-6 px-4">
      <a
        href={`tel:+351${PHONE_NUMBER}`}
        className="flex-1 flex items-center justify-center gap-3 px-6 py-4 rounded-2xl bg-[#E74C3C] text-white hover:bg-[#C0392B] transition-all duration-300 font-black shadow-lg shadow-[#E74C3C]/40 hover:scale-105 active:scale-95 text-sm uppercase tracking-widest"
      >
        <Phone size={20} />
        {t.callToOrder} - {FORMATTED_PHONE}
      </a>
    </div>
  );
};

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('pt');
  const t = translations[lang];

  const [activeCategory, setActiveCategory] = useState(MENU_DATA[0].id);
  const [searchTerm, setSearchTerm] = useState('');
  const [isPrintModalOpen, setIsPrintModalOpen] = useState(false);
  const [isQRCodeModalOpen, setIsQRCodeModalOpen] = useState(false);
  const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);
  const [isNotepadOpen, setIsNotepadOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);

  const [masterMenu, setMasterMenu] = useState<Category[]>(MENU_DATA);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);

   const loadMenu = async () => {
    setIsLoading(true);
    setApiError(null);
    try {
      setMasterMenu(MENU_DATA); 
    } catch (error: any) {
      setApiError(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  const syncMenuToUpstash = async () => {
    setIsSaving(true);
    setSaveSuccess(false);
    try {
      const response = await fetch('/api/menu', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(masterMenu)
      });

      if (!response.ok) throw new Error('Erro ao salvar no servidor.');

      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 3000);
    } catch (error: any) {
      alert(`Erro na sincronização: ${error.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  useEffect(() => {
    loadMenu();
    const savedAdminStatus = localStorage.getItem('pizzaria_fenicia_is_admin') === 'true';
    const savedCart = localStorage.getItem('pizzaria_fenicia_cart');
    if (savedCart) try { setCartItems(JSON.parse(savedCart)); } catch (e) {}
    setIsAdmin(savedAdminStatus);
  }, []);

  useEffect(() => {
    localStorage.setItem('pizzaria_fenicia_cart', JSON.stringify(cartItems));
  }, [cartItems]);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
      const sections = masterMenu.map(cat => document.getElementById(cat.id));
      const scrollPos = window.scrollY + 200;
      for (let i = sections.length - 1; i >= 0; i--) {
        const section = sections[i];
        if (section && section.offsetTop <= scrollPos) {
          setActiveCategory(masterMenu[i].id);
          break;
        }
      }
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [masterMenu]);

  const updateMenuItem = (itemId: string, updates: Partial<MenuItem>) => {
    const newMenu = masterMenu.map(cat => ({
      ...cat,
      items: cat.items.map(item => item.id === itemId ? { ...item, ...updates } : item)
    }));
    setMasterMenu(newMenu);
  };

  const handleIngredientsUpdate = (itemId: string, l: Language, text: string) => {
    const newMenu = masterMenu.map(cat => ({
      ...cat,
      items: cat.items.map(item => item.id === itemId ? {
        ...item,
        ingredients: { ...item.ingredients, [l]: text }
      } : item)
    }));
    setMasterMenu(newMenu);
  };

  const addToCart = (item: MenuItem) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const updateCartQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item));
  };

  const removeFromCart = (id: string) => setCartItems(prev => prev.filter(item => item.id !== id));
  const clearCart = () => setCartItems([]);
  const handleLogin = () => { setIsAdmin(true); localStorage.setItem('pizzaria_fenicia_is_admin', 'true'); };
  const handleLogout = () => { setIsAdmin(false); localStorage.setItem('pizzaria_fenicia_is_admin', 'false'); };

  const filteredMenu = useMemo(() => {
    if (!searchTerm) return masterMenu;
    const term = searchTerm.toLowerCase();
    return masterMenu.map(cat => ({
      ...cat,
      items: cat.items.filter(item => 
        item.name.toLowerCase().includes(term) ||
        Object.values(item.ingredients).some(ing => (ing as string).toLowerCase().includes(term))
      )
    })).filter(cat => cat.items.length > 0);
  }, [searchTerm, masterMenu]);

  const scrollToCategory = (id: string) => {
    const el = document.getElementById(id);
    if (el) {
      window.scrollTo({ top: el.offsetTop - 80, behavior: 'smooth' });
      setActiveCategory(id);
    }
  };

  const CATEGORY_COLORS: Record<string, string> = {
    'entradas': '#FF5733', 'saladas': '#2ECC71', 'massas': '#F1C40F',
    'especialidades': '#9B59B6', 'pizzas-classicas': '#E74C3C', 'pizzas-especiais': '#C0392B',
  };

  return (
    <div className="min-h-screen bg-[#FAF9F6]">
      {isAdmin && (
        <div className="bg-[#1D3C18] text-white py-3 px-4 sticky top-0 z-[110] shadow-2xl flex flex-wrap items-center justify-between gap-4 border-b border-white/10 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 font-black text-[10px] uppercase tracking-widest text-[#27AE60]">
              <Unlock size={14} /> {t.adminPanel}
            </div>
            <button 
              onClick={syncMenuToUpstash}
              disabled={isSaving}
              className={`flex items-center gap-2 px-6 py-2 rounded-full font-black text-[11px] uppercase tracking-widest transition-all shadow-lg active:scale-95 ${
                saveSuccess 
                  ? 'bg-green-500 text-white' 
                  : 'bg-[#27AE60] text-white hover:bg-[#1E8449]'
              } ${isSaving ? 'opacity-70 cursor-wait' : ''}`}
            >
              {isSaving ? <RefreshCcw size={14} className="animate-spin" /> : saveSuccess ? <CheckCircle size={14} /> : <CloudUpload size={14} />}
              {saveSuccess ? 'OK!' : t.updateMenu}
            </button>
          </div>
          <button onClick={handleLogout} className="text-[10px] font-black uppercase tracking-widest bg-white/10 hover:bg-white/20 px-4 py-2 rounded-full border border-white/20 transition-all text-white">
            {t.logout}
          </button>
        </div>
      )}

      {apiError && !isAdmin && (
        <div className="bg-amber-100 text-amber-900 py-2 px-4 text-center text-[10px] font-black uppercase tracking-widest border-b border-amber-200">
          <div className="flex items-center justify-center gap-2"><AlertTriangle size={12} /> Offline Mode - Loading local data</div>
        </div>
      )}

      <div className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-500 flex justify-center pt-4 px-4 pointer-events-none ${isAdmin ? 'mt-14' : ''}`}>
        <div className="pointer-events-auto scale-110 sm:scale-125 transform transition-all duration-500">
          <LanguageSelector currentLang={lang} onLangChange={setLang} />
        </div>
      </div>

      <header className="relative h-[85vh] flex items-center justify-center overflow-hidden bg-white">
        <div className="absolute inset-0 z-0 overflow-hidden">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[110vw] md:w-[85vh] h-[110vw] md:h-[85vh] animate-[spin_80s_linear_infinite]">
            <img src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=1200&q=80" className="w-full h-full object-cover rounded-full shadow-[0_0_150px_rgba(231,76,60,0.6)] saturate-[1.8] contrast-[1.2] brightness-[1.1]" alt="Hero" />
          </div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(255,255,255,0.05)_0%,white_85%)] z-[1]"></div>
        </div>
        <div className="relative z-10 text-center px-4 max-w-4xl animate-in fade-in duration-1000 mt-20">
          <div className="bg-white/80 backdrop-blur-md p-10 md:p-16 rounded-[4rem] border border-white shadow-[0_40px_100px_rgba(0,0,0,0.15)] relative overflow-hidden">
            <h1 className="text-7xl md:text-[10rem] leading-[0.8] font-serif tracking-tighter relative z-10">
              <span className="text-[#E74C3C] block mb-2">Pizzeria</span>
              <span className="text-[#27AE60] block -mt-4 md:-mt-8">Fenicia</span>
            </h1>
          </div>
          <p className="text-gray-900 text-lg md:text-2xl font-serif italic tracking-wide max-w-lg font-black mx-auto mt-8">{t.slogan}</p>
        </div>
      </header>

      <div className="max-w-4xl mx-auto -mt-12 relative z-30"><OrderButtons lang={lang} /></div>

      <div className="sticky top-20 z-40 max-w-xl mx-auto px-4 mt-12 mb-8">
        <div className="relative group shadow-2xl rounded-[2rem] overflow-hidden bg-white/80 backdrop-blur-xl border border-white/20">
          <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none"><Search className="h-5 w-5 text-gray-400" /></div>
          <input type="text" placeholder={t.searchPlaceholder} value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="block w-full pl-14 pr-6 py-5 bg-transparent border-none focus:ring-0 focus:outline-none text-gray-900 text-base font-bold transition-all" />
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-4 mb-20 flex flex-wrap justify-center gap-3">
        {masterMenu.map((category) => (
          <button key={category.id} onClick={() => scrollToCategory(category.id)} className={`group flex items-center justify-between px-6 py-5 rounded-3xl font-black transition-all duration-300 shadow-lg ${activeCategory === category.id ? 'scale-105 shadow-2xl ring-4 ring-white z-10' : 'opacity-90 hover:opacity-100 hover:-translate-y-1'}`} style={{ backgroundColor: CATEGORY_COLORS[category.id] || '#ccc', color: 'white' }}>
            <div className="flex flex-col items-start gap-1"><span className="uppercase tracking-[0.2em] text-[11px] leading-none">{t.explore}</span><span className="text-sm uppercase tracking-tight">{category.title}</span></div>
            <div className={`p-2 rounded-2xl bg-white/20 transition-transform ${activeCategory === category.id ? 'rotate-90' : 'group-hover:translate-x-1'}`}><ArrowRight size={18} /></div>
          </button>
        ))}
      </div>

      <main className="max-w-3xl mx-auto px-4 pb-20">
        {isLoading ? (
          <div className="text-center py-20 flex flex-col items-center gap-4"><RefreshCcw size={48} className="animate-spin text-[#E74C3C]" /><p className="text-gray-400 font-black uppercase tracking-widest text-xs">{t.loadingMenu}</p></div>
        ) : filteredMenu.length === 0 ? (
          <div className="text-center py-32 opacity-30"><Search size={64} className="mx-auto mb-4" /><p className="text-gray-500 text-xl font-serif italic">{t.noItemsFound}</p></div>
        ) : (
          filteredMenu.map((category) => (
            <section key={category.id} id={category.id} className="mb-20 scroll-mt-32">
              <div className="mb-8 flex items-center gap-4 px-2"><div className="w-3 h-10 rounded-full" style={{ backgroundColor: CATEGORY_COLORS[category.id] }}></div><h2 className="text-4xl text-gray-900 font-black tracking-tighter">{category.title}</h2></div>
              <div className="bg-white rounded-[3rem] p-6 md:p-10 shadow-[0_20px_50px_rgba(0,0,0,0.05)] border border-gray-100 space-y-2">
                {category.items.map((item) => (
                  <MenuItemCard 
                    key={item.id} item={item} lang={lang} isAdmin={isAdmin}
                    onImageUpdate={(id, base64) => updateMenuItem(id, { image: base64 })}
                    onPriceUpdate={(id, price) => updateMenuItem(id, { price })}
                    onNameUpdate={(id, name) => updateMenuItem(id, { name })}
                    onNumberUpdate={(id, number) => updateMenuItem(id, { number })}
                    onIngredientsUpdate={(text) => handleIngredientsUpdate(item.id, lang, text)}
                    onAddToCart={addToCart}
                  />
                ))}
              </div>
            </section>
          ))
        )}
      </main>

      <div className="fixed bottom-8 right-8 flex flex-col gap-4 z-[140]">
        {!isAdmin && (
          <button onClick={() => setIsNotepadOpen(true)} className="relative p-5 bg-[#1D3C18] text-white rounded-[2rem] shadow-xl hover:scale-110 active:scale-90">
            <ClipboardList size={28} />
            {cartItems.length > 0 && <span className="absolute -top-2 -right-2 bg-[#E74C3C] text-white text-[10px] font-black w-7 h-7 flex items-center justify-center rounded-full border-4 border-[#FAF9F6] animate-bounce">{cartItems.reduce((s, i) => s + i.quantity, 0)}</span>}
          </button>
        )}
        <button onClick={() => setIsQRCodeModalOpen(true)} className="p-5 bg-[#27AE60] text-white rounded-[2rem] shadow-xl hover:scale-110"><QrCode size={28} /></button>
        {isAdmin && <button onClick={() => setIsPrintModalOpen(true)} className="p-5 bg-[#D4AF37] text-white rounded-[2rem] shadow-xl hover:scale-110"><Printer size={28} /></button>}
        <button onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} className={`p-5 bg-gray-900 text-white rounded-[2rem] shadow-xl transition-all duration-700 ${isScrolled ? 'translate-y-0 opacity-100' : 'translate-y-20 opacity-0 pointer-events-none'}`}><ChevronDown className="rotate-180" size={28} /></button>
      </div>

      <PrintMenuModal isOpen={isPrintModalOpen} onClose={() => setIsPrintModalOpen(false)} menuData={masterMenu} lang={lang} />
      <QRCodeModal isOpen={isQRCodeModalOpen} onClose={() => setIsQRCodeModalOpen(false)} lang={lang} />
      <AdminLoginModal isOpen={isLoginModalOpen} onClose={() => setIsLoginModalOpen(false)} onLogin={handleLogin} lang={lang} />
      <OrderNotepad isOpen={isNotepadOpen} onClose={() => setIsNotepadOpen(false)} items={cartItems} onUpdateQuantity={updateCartQuantity} onRemove={removeFromCart} onClear={clearCart} lang={lang} phoneNumber={PHONE_NUMBER} />

      <footer className="bg-white pt-24 pb-40 border-t border-gray-100 text-center relative overflow-hidden">
        <div className="max-w-4xl mx-auto px-4 relative z-10">
          <img src={CHEF_LOGO} alt="Chef" className="w-20 h-20 object-contain opacity-40 grayscale mx-auto mb-8" />
          <h3 className="text-5xl md:text-7xl text-[#1D3C18] mb-12 font-black italic tracking-tighter">Pizzeria Fenicia</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-12 max-w-2xl mx-auto mb-20">
            <div className="flex flex-col items-center gap-4"><div className="p-4 bg-[#E74C3C]/10 rounded-full text-[#E74C3C]"><MapPin size={28} /></div><p className="text-gray-900 font-black text-lg">{t.location}</p></div>
            <div className="flex flex-col items-center gap-4"><div className="p-4 bg-[#27AE60]/10 rounded-full text-[#27AE60]"><Clock size={28} /></div><p className="text-gray-900 font-black text-lg">12h-15h | 19h-22h</p></div>
          </div>
          <button onClick={() => isAdmin ? handleLogout() : setIsLoginModalOpen(true)} className="text-[9px] text-gray-300 hover:text-[#FF5733] transition-all uppercase tracking-[0.5em] font-black border border-gray-100 px-6 py-3 rounded-full">{isAdmin ? t.closePanel : t.restrictedAccess}</button>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { X, Trash2, Plus, Minus, ShoppingBag, ClipboardList, Phone } from 'lucide-react';
import { CartItem, Language } from '../types';
import { translations } from '../translations';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onUpdateQuantity: (id: string, delta: number) => void;
  onRemove: (id: string) => void;
  onClear: () => void;
  lang: Language;
  phoneNumber: string;
}

export const OrderNotepad: React.FC<Props> = ({ 
  isOpen, onClose, items, onUpdateQuantity, onRemove, onClear, lang, phoneNumber 
}) => {
  const t = translations[lang];
  if (!isOpen) return null;

  const total = items.reduce((sum, item) => {
    const priceNum = parseFloat(item.price.replace(/[^\d.]/g, '')) || 0;
    return sum + (priceNum * item.quantity);
  }, 0);

  const telLink = phoneNumber.startsWith('+') ? phoneNumber : `+351${phoneNumber}`;

  return (
    <div className="fixed inset-0 z-[150] flex items-end sm:items-center justify-end sm:p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div 
        className="bg-[#FFFDF0] w-full sm:w-[420px] max-h-[95vh] sm:max-h-[85vh] flex flex-col rounded-t-[2rem] sm:rounded-[2rem] shadow-2xl overflow-hidden border-t-8 border-[#1D3C18] animate-in slide-in-from-bottom duration-500"
      >
        <div className="p-4 bg-[#1D3C18] text-white flex items-center justify-between shadow-lg">
          <div className="flex items-center gap-2">
            <ClipboardList className="text-[#D4AF37]" size={20} />
            <div>
              <h2 className="text-lg font-serif font-bold italic">{t.myOrder}</h2>
              <p className="text-[8px] font-black uppercase tracking-[0.2em] opacity-60">{t.orderSummary}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-all">
            <X size={20} />
          </button>
        </div>

        <div 
          className="flex-1 overflow-y-auto relative"
          style={{ 
            backgroundImage: 'repeating-linear-gradient(#FFFDF0, #FFFDF0 31px, #E5E7EB 31px, #E5E7EB 32px)',
            backgroundAttachment: 'local',
            lineHeight: '32px'
          }}
        >
          {items.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full py-20 text-center opacity-30">
              <ShoppingBag size={40} className="mb-2" strokeWidth={1} />
              <p className="font-serif italic text-lg text-gray-600">{t.emptyCart}</p>
            </div>
          ) : (
            <div className="px-6 py-2">
              {items.map((item) => (
                <div key={item.id} className="min-h-[64px] flex items-center gap-3 border-b border-transparent">
                  <div className="flex-1 min-w-0 pt-1">
                    <div className="flex justify-between items-baseline">
                      <h4 className="font-black text-gray-900 text-xs sm:text-sm truncate uppercase tracking-tight">
                        {item.quantity}x {item.name}
                      </h4>
                      <span className="font-bold text-[11px] text-[#E74C3C] tabular-nums ml-2">
                        {item.price}
                      </span>
                    </div>
                  </div>

                  <div className="flex items-center gap-1.5 h-full">
                    <div className="flex items-center bg-white/80 rounded-full border border-gray-200 shadow-sm px-1">
                      <button 
                        onClick={() => onUpdateQuantity(item.id, -1)}
                        className="p-1 hover:text-[#E74C3C] transition-all"
                      >
                        <Minus size={14} />
                      </button>
                      <span className="w-5 text-center font-black text-[11px] text-gray-900 leading-none">{item.quantity}</span>
                      <button 
                        onClick={() => onUpdateQuantity(item.id, 1)}
                        className="p-1 hover:text-[#27AE60] transition-all"
                      >
                        <Plus size={14} />
                      </button>
                    </div>
                    <button 
                      onClick={() => onRemove(item.id)}
                      className="p-1.5 text-gray-300 hover:text-red-600 transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}

              <button 
                onClick={onClear}
                className="mt-6 w-full py-2 text-[9px] font-black uppercase text-gray-400 hover:text-red-500 transition-all flex items-center justify-center gap-1"
              >
                {t.clearAll}
              </button>
            </div>
          )}
        </div>

        <div className="bg-white border-t border-gray-100 p-6 shadow-[0_-10px_20px_rgba(0,0,0,0.02)]">
          <div className="flex justify-between items-center mb-5">
            <span className="font-serif italic text-xl text-gray-900">{t.total}</span>
            <span className="font-black text-2xl text-[#E74C3C]">{total.toFixed(2)}€</span>
          </div>

          <div className="space-y-3">
            <a
              href={`tel:${telLink}`}
              className="w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-black uppercase text-xs tracking-widest transition-all shadow-xl active:scale-95 bg-[#E74C3C] text-white hover:bg-[#C0392B] shadow-[#E74C3C]/30"
            >
              <Phone size={20} />
              {t.callToOrder}
            </a>
          </div>

          <p className="text-center text-[8px] text-gray-400 mt-4 uppercase font-bold tracking-tight">
            {t.orderNote}
          </p>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { QRCodeSVG } from 'qrcode.react';
import { X, Share2, Copy, Check } from 'lucide-react';
import { Language } from '../types';
import { translations } from '../translations';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  lang: Language;
}

export const QRCodeModal: React.FC<Props> = ({ isOpen, onClose, lang }) => {
  const [copied, setCopied] = React.useState(false);
  const t = translations[lang];

  if (!isOpen) return null;

  const currentUrl = window.location.origin;

  const handleCopy = () => {
    navigator.clipboard.writeText(currentUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Pizzeria Fenicia Menu`,
          url: currentUrl,
        });
      } catch (err) {
        console.error(err);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-[3rem] w-full max-w-sm overflow-hidden shadow-2xl relative animate-in zoom-in duration-500">
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 p-2 rounded-full bg-gray-50 text-gray-400 hover:bg-red-50 hover:text-red-500 transition-all z-10"
        >
          <X size={20} />
        </button>

        <div className="p-10 flex flex-col items-center text-center">
          <div className="mb-6">
            <h2 className="text-3xl font-serif font-black text-gray-900">{t.shareMenu}</h2>
            <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest mt-1">{t.pointCamera}</p>
          </div>

          <div className="p-8 bg-white border-2 border-gray-50 rounded-[2.5rem] shadow-sm mb-8 transform transition-transform hover:scale-105 duration-500">
            <QRCodeSVG 
              value={currentUrl} 
              size={180} 
              level="H" 
              includeMargin={false}
              bgColor="#ffffff"
              fgColor="#000000"
            />
          </div>

          <div className="flex flex-col gap-3 w-full">
            <button 
              onClick={handleCopy}
              className={`w-full flex items-center justify-center gap-3 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${
                copied ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              {copied ? <Check size={16} /> : <Copy size={16} />}
              {copied ? t.linkCopied : t.copyLink}
            </button>

            {navigator.share && (
              <button 
                onClick={handleShare}
                className="w-full flex items-center justify-center gap-3 py-4 rounded-2xl bg-[#E74C3C] text-white font-black uppercase text-[10px] tracking-widest hover:bg-[#C0392B] transition-all shadow-lg shadow-[#E74C3C]/20"
              >
                <Share2 size={16} />
                {t.sendFriends}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { X, Lock, ShieldCheck, AlertCircle } from 'lucide-react';
import { Language } from '../types';
import { translations } from '../translations';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onLogin: () => void;
  lang: Language;
}

export const AdminLoginModal: React.FC<Props> = ({ isOpen, onClose, onLogin, lang }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const t = translations[lang];

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const currentPassword = localStorage.getItem('admin_password') || 'Fenicía123';

    if (password === currentPassword) {
      onLogin();
      setPassword('');
      setError(false);
      onClose();
    } else {
      setError(true);
      setPassword('');
    }
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm">
      <div className="bg-white rounded-[1rem] w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-300">
        <div className="bg-[#E74C3C] p-10 flex flex-col items-center text-white relative">
          <button 
            onClick={onClose}
            className="absolute top-4 right-4 p-2 rounded-full hover:bg-white/20 transition-all"
          >
            <X size={20} />
          </button>
          <div className="w-16 h-16 border-2 border-white/50 rounded-full flex items-center justify-center mb-4">
            <Lock size={32} strokeWidth={1.5} />
          </div>
          <h2 className="text-3xl font-serif uppercase tracking-widest text-center">{t.managementArea}</h2>
          <p className="text-white/90 text-[10px] font-bold mt-2 uppercase tracking-widest">{t.authorizedOnly}</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 bg-white">
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">
                {t.password}
              </label>
              <div className="relative">
                <input
                  autoFocus
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className={`w-full px-4 py-4 bg-gray-50 border-2 rounded-xl focus:outline-none transition-all font-bold text-center tracking-widest ${
                    error ? 'border-red-500 bg-red-50 text-red-900' : 'border-transparent focus:border-[#E74C3C]'
                  }`}
                  placeholder="••••••••"
                />
              </div>
              {error && (
                <div className="flex items-center justify-center gap-2 text-red-500 text-[10px] font-black uppercase mt-2 animate-bounce">
                  <AlertCircle size={14} />
                  {t.wrongPassword}
                </div>
              )}
            </div>

            <button
              type="submit"
              className="w-full py-4 bg-[#1D3C18] text-white rounded-xl font-black uppercase tracking-[0.2em] text-xs shadow-lg hover:bg-black transition-all active:scale-95 flex items-center justify-center gap-3"
            >
              <ShieldCheck size={18} />
              {t.accessPanel}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { X, Printer, Layout, Columns as ColumnsIcon, Maximize, Image as ImageIcon, Droplets, Type, Check, RectangleHorizontal } from 'lucide-react';
import { Category, Language } from '../types';
import { translations } from '../translations';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  menuData: Category[];
  lang: Language;
}

type PaperSize = 'A5' | 'A4' | 'A3' | 'A2' | 'A1';
type FontSize = 'XS' | 'SM' | 'NOR' | 'LG';
type Orientation = 'portrait' | 'landscape';

export const PrintMenuModal: React.FC<Props> = ({ isOpen, onClose, menuData, lang }) => {
  const t = translations[lang];
  const [paperSize, setPaperSize] = useState<PaperSize>('A4');
  const [orientation, setOrientation] = useState<Orientation>('portrait');
  const [showImages, setShowImages] = useState(true);
  const [grayscale, setGrayscale] = useState(false);
  const [fontSize, setFontSize] = useState<FontSize>('NOR');
  const [customCols, setCustomCols] = useState<number | 'auto'>('auto');

  if (!isOpen) return null;

  const handlePrint = () => {
    window.print();
  };

  const getColumns = () => {
    if (customCols !== 'auto') return customCols;
    if (orientation === 'landscape') {
        if (paperSize === 'A5') return 1;
        if (paperSize === 'A4') return 2;
        if (paperSize === 'A3') return 3;
        return 4;
    }
    if (paperSize === 'A4') return 1;
    if (paperSize === 'A3') return 2;
    if (paperSize === 'A2') return 3;
    if (paperSize === 'A1') return 4;
    return 1;
  };

  const getPageDimensions = () => {
    const isPortrait = orientation === 'portrait';
    switch (paperSize) {
      case 'A5': return isPortrait ? { w: '148mm', h: '210mm' } : { w: '210mm', h: '148mm' };
      case 'A3': return isPortrait ? { w: '297mm', h: '420mm' } : { w: '420mm', h: '297mm' };
      case 'A2': return isPortrait ? { w: '420mm', h: '594mm' } : { w: '594mm', h: '420mm' };
      case 'A1': return isPortrait ? { w: '594mm', h: '841mm' } : { w: '841mm', h: '594mm' };
      default: return isPortrait ? { w: '210mm', h: '297mm' } : { w: '297mm', h: '210mm' };
    }
  };

  const getFontSizeClass = () => {
    switch (fontSize) {
      case 'XS': return 'text-[9px]';
      case 'SM': return 'text-[11px]';
      case 'LG': return 'text-[15px]';
      default: return 'text-[13px]';
    }
  };

  const dims = getPageDimensions();
  const cols = getColumns();

  return (
    <div className="fixed inset-0 z-[160] flex items-center justify-center bg-black/90 backdrop-blur-md print:bg-white print:static overflow-hidden">
      <div className="absolute left-4 top-4 bottom-4 z-[170] flex flex-col w-72 print:hidden animate-in slide-in-from-left duration-500">
        <div className="bg-white rounded-[2rem] h-full flex flex-col shadow-2xl overflow-hidden border border-white/20">
          <div className="p-4 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
            <h2 className="text-gray-900 font-black uppercase tracking-tight text-base font-serif">{t.adjustments}</h2>
            <button onClick={onClose} className="p-1.5 hover:bg-gray-200 rounded-full transition-all text-gray-400">
              <X size={16} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-thin scrollbar-thumb-gray-200">
            <div className="space-y-1.5">
              <h3 className="text-gray-400 font-black uppercase tracking-widest text-[8px] flex items-center gap-1.5">
                <Maximize size={10} /> {t.paper}
              </h3>
              <div className="grid grid-cols-3 gap-1">
                {(['A5', 'A4', 'A3', 'A2', 'A1'] as PaperSize[]).map((size) => (
                  <button
                    key={size}
                    onClick={() => setPaperSize(size)}
                    className={`py-1.5 rounded-lg font-black transition-all border-2 text-[9px] ${
                      paperSize === size 
                        ? 'bg-[#E74C3C] text-white border-[#E74C3C]' 
                        : 'bg-white text-gray-400 border-gray-100'
                    }`}
                  >
                    {size}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-1.5">
              <h3 className="text-gray-400 font-black uppercase tracking-widest text-[8px] flex items-center gap-1.5">
                <Layout size={10} /> {t.orientation}
              </h3>
              <div className="flex gap-1">
                  <button 
                      onClick={() => setOrientation('portrait')}
                      className={`flex-1 flex items-center justify-center gap-1.5 py-1.5 rounded-lg border-2 transition-all font-black text-[9px] ${orientation === 'portrait' ? 'bg-gray-900 text-white border-gray-900' : 'bg-white text-gray-400 border-gray-100'}`}
                  >
                      <RectangleHorizontal size={10} className="rotate-90" /> {t.portrait}
                  </button>
                  <button 
                      onClick={() => setOrientation('landscape')}
                      className={`flex-1 flex items-center justify-center gap-1.5 py-1.5 rounded-lg border-2 transition-all font-black text-[9px] ${orientation === 'landscape' ? 'bg-gray-900 text-white border-gray-900' : 'bg-white text-gray-400 border-gray-100'}`}
                  >
                      <RectangleHorizontal size={10} /> {t.landscape}
                  </button>
              </div>
            </div>

            <div className="space-y-1.5">
              <h3 className="text-gray-400 font-black uppercase tracking-widest text-[8px] flex items-center gap-1.5">
                <Type size={10} /> {t.fontSize}
              </h3>
              <div className="flex gap-1 p-1 bg-gray-50 rounded-lg">
                  {(['XS', 'SM', 'NOR', 'LG'] as FontSize[]).map((f) => (
                      <button 
                        key={f} 
                        onClick={() => setFontSize(f)} 
                        className={`flex-1 py-1 rounded-md text-[8px] font-black transition-all ${fontSize === f ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-400'}`}
                      >
                        {f}
                      </button>
                  ))}
              </div>
            </div>

            <div className="space-y-1.5">
              <h3 className="text-gray-400 font-black uppercase tracking-widest text-[8px] flex items-center gap-1.5">
                <ColumnsIcon size={10} /> {t.columns}
              </h3>
              <div className="flex gap-1 p-1 bg-gray-50 rounded-lg">
                  {['auto', 1, 2, 3, 4].map((c) => (
                      <button 
                        key={c} 
                        onClick={() => setCustomCols(c as any)} 
                        className={`flex-1 py-1 rounded-md text-[8px] font-black transition-all uppercase ${customCols === c ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-400'}`}
                      >
                        {c}
                      </button>
                  ))}
              </div>
            </div>

            <div className="pt-1 space-y-1.5">
              <button 
                onClick={() => setShowImages(!showImages)}
                className={`w-full flex items-center justify-between px-3 py-2 rounded-lg font-black text-[9px] transition-all border-2 ${
                  showImages ? 'bg-[#27AE60]/5 text-[#27AE60] border-[#27AE60]/20' : 'bg-white text-gray-400 border-gray-100'
                }`}
              >
                <div className="flex items-center gap-2"><ImageIcon size={12} /> {t.photos}</div>
                {showImages && <Check size={12} />}
              </button>

              <button 
                onClick={() => setGrayscale(!grayscale)}
                className={`w-full flex items-center justify-between px-3 py-2 rounded-lg font-black text-[9px] transition-all border-2 ${
                  grayscale ? 'bg-gray-900/5 text-gray-900 border-gray-900/20' : 'bg-white text-gray-400 border-gray-100'
                }`}
              >
                <div className="flex items-center gap-2"><Droplets size={12} /> {t.bw}</div>
                {grayscale && <Check size={12} />}
              </button>
            </div>
          </div>

          <div className="p-4 border-t border-gray-100 bg-gray-50/50">
            <button 
              onClick={handlePrint}
              className="w-full flex items-center justify-center gap-2 py-3 rounded-xl bg-[#E74C3C] text-white font-black uppercase tracking-widest text-[10px] hover:bg-[#C0392B] transition-all shadow-xl shadow-[#E74C3C]/20 active:scale-95"
            >
              <Printer size={14} />
              {t.print}
            </button>
          </div>
        </div>
      </div>

      <div className="w-full h-full overflow-auto flex justify-center py-10 pl-72 print:p-0 print:m-0 print:overflow-visible scrollbar-hide">
        <div 
          id="printable-menu"
          className={`bg-white shadow-2xl print:shadow-none relative print:m-0 print:border-none ${grayscale ? 'grayscale contrast-125' : ''}`}
          style={{
            width: dims.w,
            minHeight: dims.h,
            padding: '12mm',
          }}
        >
          <div className="flex flex-col h-full bg-white">
            <div className="text-center mb-8 w-full">
              <p className="text-[#D4AF37] font-serif text-lg tracking-[0.3em] mb-0.5 uppercase">Cucina Italiana</p>
              <h1 className="text-5xl text-[#E74C3C] font-serif leading-[0.8] tracking-tighter">Pizzeria</h1>
              <h1 className="text-6xl text-[#27AE60] font-serif leading-[0.8] tracking-tighter -mt-1">Fenicia</h1>
              <div className="flex items-center justify-center gap-4 my-3">
                <div className="h-[1px] w-10 bg-gray-100"></div>
                <p className="uppercase tracking-[0.4em] text-[7px] font-black text-gray-300">Tavira • Algarve</p>
                <div className="h-[1px] w-10 bg-gray-100"></div>
              </div>
            </div>

            <div 
              className="w-full"
              style={{ 
                display: 'block',
                columnCount: cols,
                columnGap: '10mm',
                columnRule: '1px solid #f9fafb'
              }}
            >
              {menuData.map((category) => (
                <div key={category.id} className="break-inside-avoid mb-6">
                  <div className="flex items-center gap-2 mb-3 pb-1 border-b-2 border-[#E74C3C]/10">
                    <div className="w-1 h-5 bg-[#27AE60]"></div>
                    <h2 className="text-base font-serif text-[#1D3C18] uppercase tracking-wide italic font-black">
                      {category.title}
                    </h2>
                  </div>
                  <div className="space-y-3">
                    {category.items.map((item) => (
                      <div key={item.id} className={`flex gap-2.5 border-b border-gray-50 pb-2.5 last:border-none last:pb-0 break-inside-avoid ${getFontSizeClass()}`}>
                        {showImages && (
                          <div className="w-10 h-10 flex-shrink-0 bg-gray-50 rounded-lg overflow-hidden border border-gray-100 mt-0.5">
                            <img src={item.image} className="w-full h-full object-cover" alt="" />
                          </div>
                        )}
                        <div className="flex-1 min-w-0">
                          <div className="flex justify-between items-baseline gap-1.5 mb-0.5">
                            <span className="font-black text-gray-900 uppercase tracking-tighter truncate">
                              {item.number && <span className="text-[0.7em] text-[#E74C3C] mr-1 font-mono">#{item.number}</span>}
                              {item.name}
                            </span>
                            <span className="font-black text-[#E74C3C] tabular-nums whitespace-nowrap">{item.price}</span>
                          </div>
                          <p className="text-[0.85em] text-gray-500 italic leading-tight font-medium">
                            {item.ingredients[lang] || item.ingredients['pt']}
                          </p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

